# Category: kong_rate_limit_disabled

import requests
import json

class KongAdminAPI:
    def __init__(self, base_url):
        self.base_url = base_url.rstrip('/')
        self.session = requests.Session()
        self.session.headers.update({'Content-Type': 'application/json'})
    
    def create_service(self, name, url, protocol='http'):
        """Create a service in Kong"""
        service_data = {
            "name": name,
            "url": url,
            "protocol": protocol
        }
        
        response = self.session.post(
            f"{self.base_url}/services",
            json=service_data
        )
        return response.json()
    
    def create_route(self, service_id, hosts=None, paths=None, methods=None):
        """Create a route for a service"""
        route_data = {
            "service": {"id": service_id}
        }
        
        if hosts:
            route_data["hosts"] = hosts
        if paths:
            route_data["paths"] = paths
        if methods:
            route_data["methods"] = methods
            
        response = self.session.post(
            f"{self.base_url}/routes",
            json=route_data
        )
        return response.json()
    
    def create_upstream(self, name, algorithm='roundrobin'):
        """Create an upstream target"""
        upstream_data = {
            "name": name,
            "algorithm": algorithm
        }
        
        response = self.session.post(
            f"{self.base_url}/upstreams",
            json=upstream_data
        )
        return response.json()
    
    def create_target(self, upstream_id, target, weight=1):
        """Create a target for an upstream"""
        target_data = {
            "target": target,
            "weight": weight
        }
        
        response = self.session.post(
            f"{self.base_url}/upstreams/{upstream_id}/targets",
            json=target_data
        )
        return response.json()
    
    def get_service(self, service_id):
        """Get a service by ID"""
        response = self.session.get(f"{self.base_url}/services/{service_id}")
        return response.json()
    
    def get_route(self, route_id):
        """Get a route by ID"""
        response = self.session.get(f"{self.base_url}/routes/{route_id}")
        return response.json()

# Example usage
if __name__ == "__main__":
    kong = KongAdminAPI("http://localhost:8001")
    
    # Create a service
    service = kong.create_service("my-service", "http://httpbin.org")
